insert into codex_workflows (id, data) values
  ('wf-daily', $relay${"id":"wf-daily","name":"Daily report flow","trigger":"17:00 IST + 22:00 nudge","agents":["Nudge","Concierge","Scribe (form)"],"outputs":["daily_reports"],"version":"v4"}$relay$::jsonb),
  ('wf-weekly', $relay${"id":"wf-weekly","name":"Weekly rollup flow","trigger":"Mon 06:00 IST","agents":["Rollup"],"outputs":["weekly_reports"],"version":"v3"}$relay$::jsonb),
  ('wf-monthly', $relay${"id":"wf-monthly","name":"Monthly worklog flow","trigger":"1st of month","agents":["Ledger","Briefer"],"outputs":["monthly_worklogs","checkin_briefs"],"version":"v2"}$relay$::jsonb),
  ('wf-mom', $relay${"id":"wf-mom","name":"MOM → tasks flow","trigger":"New MOM uploaded","agents":["Scribe","Dispatcher","Cartographer"],"outputs":["action_items","tasks","graph_nodes"],"version":"v3"}$relay$::jsonb),
