-- Relay seed — generated from data.js. Run after 01_schema.sql + 02_rls.sql.
-- Order respects FKs (employees + weekly_summaries first).
set session_replication_role = replica; -- defer FK checks during load

on conflict (id) do update set email = excluded.email, name = excluded.name, initials = excluded.initials, manager_id = excluded.manager_id, dept = excluded.dept, sub = excluded.sub, role_level = excluded.role_level, title = excluded.title, is_cross_dept = excluded.is_cross_dept, data = excluded.data;

on conflict (id) do update set data = excluded.data;

on conflict (id) do update set bd_id = excluded.bd_id, product_id = excluded.product_id, data = excluded.data;

-- dept_health: no rows

