-- weekly_comments: no rows

-- moms: no rows

-- engram_interactions: no rows

-- eval_sets: no rows

-- guideline_proposals: no rows

-- farm_agents: no rows

on conflict (id) do update set data = excluded.data;

on conflict (id) do update set data = excluded.data;

on conflict (id) do update set data = excluded.data;

